/**
 * Sum mandate's amounts
 * 
 * by Cinthia Romero
 * modified by Adriana Centellas
 */
var mandatesGrid = this.PE_MANDATES;
var mandatesGridRows = Object.keys(mandatesGrid).length;
var totalCents = 0;

if (mandatesGrid !== undefined && mandatesGrid !== null && mandatesGridRows > 0) {
    for (var i = 0; i < mandatesGridRows; i++) {
        var amount = mandatesGrid[i]["PE_MANDATE_AMOUNT"];
        var amountInCents = Math.round(amount * 100); // convert to cents
        totalCents += amountInCents;
    }
}

var totalFinal = totalCents / 100; // convert back to dollars
return totalFinal;

/**
 * Sum mandate's percentages
 * 
 * by Cinthia Romero
 */
var mandatesGrid = this.PE_MANDATES;
var mandatesGridRows = Object.keys(mandatesGrid).length;
var totalPercentages = 0;
if (mandatesGrid != undefined && mandatesGrid != null && mandatesGridRows > 0) {
    for (var i = 0; i < mandatesGridRows; i++) {
        totalPercentages = totalPercentages + mandatesGrid[i]["PE_MANDATE_PERCENTAGE_DEAL"];
    }
}
return totalPercentages;

/**
 * Show mandates total error message
 * 
 * by Cinthia Romero
 */
var showMandatesErrorMessage = "NO";
if (this.PE_MANDATE_TOTAL_AMOUNT != this.PE_MANDATE_INITIAL_TOTAL_AMOUNT) {
    showMandatesErrorMessage = "YES"
}
return showMandatesErrorMessage;

/*
* Required if currency is other
* by Ana Castillo
*/
let currency = this.PE_CURRENCY;
let saveSubmit = this.PE_SAVE_SUBMIT_DT1;
let other = false;
//Change to required if currency is Other and it is not SAVE
if (currency == "OTHER" && saveSubmit != "SAVE") {
    other = true;
}
return other;

var PE_MANDATES_ONLY_NAMES = this.PE_MANDATES.map(function(mandate) {
    return {
        NAME: mandate.PE_MANDATE_NAME,
        COINVESTOR: mandate.PE_MANDATE_NAME_SL.CO_INVESTOR
    };
});
var encodedPE_MANDATES = encodeURIComponent(JSON.stringify(PE_MANDATES_ONLY_NAMES));
return encodedPE_MANDATES;

/**
 * Correction the conditions != null and != undefined and != ""
 * 
 * by Ignacio Cardozo
 */

var legalReviewComent = this.PE_LEGAL_REVIEW_RED_FLAG_COMMENTS; 
var validationReviewComent = false
if (legalReviewComent != undefined && legalReviewComent != null && legalReviewComent != "") {
    validationReviewComent = true;
}
return validationReviewComent;

/**
 * Correction the conditions != null and != undefined and != ""
 * 
 * by Ignacio Cardozo
 */

var redFlagTax = this.PE_RED_FLAG_TAX_REVIEW; 
var validationRedFlagTax = false
if (redFlagTax != undefined && redFlagTax != null && redFlagTax != "") {
    validationRedFlagTax = true;
}
return validationRedFlagTax;

/**
 * Correction the conditions != null and != undefined and != ""
 * 
 * by Ignacio Cardozo
 */

var redFlagTaxComments = this.PE_RED_TAX_REVIEW_RED_FLAG_COMMENTS; 
var validationRedFlagTaxCom = false
if (redFlagTaxComments != undefined && redFlagTaxComments != null && redFlagTaxComments != "") {
    validationRedFlagTaxCom = true;
}
return validationRedFlagTaxCom;

/**
 * Correction the Button eliminate loop, when lenght loop is 1.
 * 
 * by Ignacio Cardozo
 */

let loop = this.PE_MANDATES;
$("[title='Delete Item']").show();
if (loop.length == 1) {
    $("[title='Delete Item']").hide();
}

/**
 * PE_IC_SPONSOR_LABEL
 * 
 * by Adriana Centellas
 */

let fullName = "";

for (let i = 0; i < this.PE_DEAL_IC_SPONSOR_OPTIONS.length; i++) {
    if (this.PE_DEAL_IC_SPONSOR_OPTIONS[i].ID == this.PE_IC_SPONSOR) {
        fullName = this.PE_DEAL_IC_SPONSOR_OPTIONS[i].FULL_NAME;
        break;
    }
}

return fullName;

let validation = {
    "moicRequired": 1,
    "moicValid": 0,
    "irrRequired": 1,
    "irrValid": 0,
    "allValid": 0
}
let dealType = this.PE_DEAL_TYPE;
let moicValue = this.PE_BASE_CASE_MOIC;
let irrValue = this.PE_BASE_CASE_IRR;
if (dealType == "Primary") {
    validation.moicRequired = 0;
    validation.moicValid = 1;
    validation.irrRequired = 0;
    validation.irrValid = 1;
    validation.allValid = 1;
} else {
    validation.moicRequired = 1;
    validation.moicValid = 0;
    if (moicValue != '' && moicValue != 0) {
        validation.moicValid = 1;
    }
    validation.irrRequired = 1;
    validation.irrValid = 0;
    if (irrValue != '' && irrValue != 0) {
        validation.irrValid = 1;
    }
}
if ((validation.moicValid == 1 && validation.irrValid == 1) || (validation.moicRequired == 0 && validation.irrRequired == 0)) {
    validation.allValid = 1;
}
return validation;

/**
 * Set users without signatures
 * 
 * by Favio Mollinedo
 */

const targetDiv = $("#messagesDiv");
$('#messagesDiv').empty();
const ulElement = $("<ul style='list-style-type: disc; padding-left: 30px;'>").appendTo(targetDiv);
this.MANDATE_SIGN_VALIDATION.USER_MESSAGE.forEach(message => {
    $("<li>").html(`<b>${message}</b>`).appendTo(ulElement);
});

let isEmpty = 
    !this.PE_REAPPROVAL_IC_NEEDED;

if (isEmpty) {
    return true;
} else {
    if (this.PE_REAPPROVAL_IC_NEEDED === "YES") {
        return true;
    } else if (this.PE_REAPPROVAL_IC_NEEDED === "NO") {
        return false;
    }
}

let isValid = 0;
this.PE_MANDATES.forEach(mandate => {
    if (mandate["PE_MANDATE_CO_INVESTOR"] == "NO") {
        isValid = 1;
    }
});
return isValid;
